import { useEffect, useState, useCallback } from "react";
import "./CompanyDashboard.scss";

export default function CompanyDashboard() {
  const [bugs, setBugs] = useState([]);
  const [filter, setFilter] = useState("all");

  // approve modal
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [selectedBug, setSelectedBug] = useState(null);
  const [severity, setSeverity] = useState("low");
  const [reward, setReward] = useState("");

  // duplicate modal
  const [showDuplicateModal, setShowDuplicateModal] = useState(false);
  const [duplicateBugId, setDuplicateBugId] = useState("");

  const token = localStorage.getItem("token");

  /* ================= FETCH BUGS ================= */
  const fetchCompanyBugs = useCallback(() => {
    fetch("http://localhost:5000/api/bugs/company/bugs", {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then((res) => res.json())
      .then((data) => setBugs(data.bugs || []));
  }, [token]);

  useEffect(() => {
    const role = localStorage.getItem("role");

    if (!token) return (window.location.href = "/");
    if (role !== "company" && role !== "admin")
      return (window.location.href = "/hacker");

    fetchCompanyBugs();
  }, [fetchCompanyBugs, token]);

  const filteredBugs =
    filter === "all" ? bugs : bugs.filter((b) => b.status === filter);

  /* ================= ACTIONS ================= */

  const openApprove = (bug) => {
    setSelectedBug(bug);
    setSeverity("low");
    setReward("");
    setShowApproveModal(true);
  };

  const approveBug = async () => {
    if (!reward || reward <= 0) return;

    await fetch(`http://localhost:5000/api/bugs/validate/${selectedBug._id}`, {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({
        status: "approved",
        severity,
        reward: Number(reward),
      }),
    });

    setShowApproveModal(false);
    fetchCompanyBugs();
  };

  const rejectBug = async (id) => {
    await fetch(`http://localhost:5000/api/bugs/validate/${id}`, {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({ status: "rejected" }),
    });

    fetchCompanyBugs();
  };

  const openDuplicate = (bug) => {
    setSelectedBug(bug);
    setDuplicateBugId("");
    setShowDuplicateModal(true);
  };

  const confirmDuplicate = async () => {
    if (!duplicateBugId) return;

    await fetch(`http://localhost:5000/api/bugs/validate/${selectedBug._id}`, {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({
        status: "duplicate",
        duplicateOf: duplicateBugId,
      }),
    });

    setShowDuplicateModal(false);
    fetchCompanyBugs();
  };

  /* ================= UI ================= */

  return (
    <div className="company-dashboard">
      {/* HEADER */}
      <header className="company-header">
        <h1>🏢 Company Dashboard</h1>
        <button
          className="logout-btn"
          onClick={() => {
            localStorage.clear();
            window.location.href = "/";
          }}
        >
          Logout
        </button>
      </header>

      {/* FILTER BAR */}
      <div className="filter-bar">
        {["all", "submitted", "approved", "rejected", "duplicate"].map((f) => (
          <button
            key={f}
            className={filter === f ? "active" : ""}
            onClick={() => setFilter(f)}
          >
            {f.toUpperCase()}
          </button>
        ))}
      </div>

      {/* BUG LIST */}
      <div className="bug-list">
        {filteredBugs.length === 0 ? (
          <p className="muted">No bugs found.</p>
        ) : (
          filteredBugs.map((bug) => (
            <div className="bug-card" key={bug._id}>
              <div className="bug-top">
                <h3>{bug.title}</h3>
                <span className={`status ${bug.status}`}>
                  {bug.status}
                </span>
              </div>

              {/* BUG ID */}
              <div className="bug-id">ID: {bug._id}</div>

              <p className="bug-desc">{bug.description}</p>

              <div className="bug-meta">
                <span className={`severity ${bug.severity}`}>
                  {bug.severity}
                </span>
                <span className="email">
                  🧑‍💻 {bug.submittedBy?.email}
                </span>
              </div>

              {bug.status === "submitted" && (
                <div className="bug-actions">
                  <button className="approve" onClick={() => openApprove(bug)}>
                    Approve
                  </button>
                  <button className="reject" onClick={() => rejectBug(bug._id)}>
                    Reject
                  </button>
                  <button
                    className="duplicate"
                    onClick={() => openDuplicate(bug)}
                  >
                    Mark Duplicate
                  </button>
                </div>
              )}

              {bug.status === "duplicate" && bug.duplicateOf && (
                <div className="duplicate-ref">
                  Duplicate of: {bug.duplicateOf}
                </div>
              )}
            </div>
          ))
        )}
      </div>

      {/* APPROVE MODAL */}
      {showApproveModal && (
        <div className="modal-backdrop">
          <div className="modal-box">
            <h2>Approve Bug</h2>

            <label>Severity</label>
            <select
              value={severity}
              onChange={(e) => setSeverity(e.target.value)}
            >
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
              <option value="critical">Critical</option>
            </select>

            <label>Reward (₹)</label>
            <input
              type="number"
              value={reward}
              onChange={(e) => setReward(e.target.value)}
            />

            <div className="modal-actions">
              <button className="approve" onClick={approveBug}>
                Confirm
              </button>
              <button
                className="reject"
                onClick={() => setShowApproveModal(false)}
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      {/* DUPLICATE MODAL */}
      {showDuplicateModal && (
        <div className="modal-backdrop">
          <div className="modal-box">
            <h2>Mark Bug as Duplicate</h2>

            <label>Original Bug ID</label>
            <input
              type="text"
              placeholder="Paste old bug ID"
              value={duplicateBugId}
              onChange={(e) => setDuplicateBugId(e.target.value)}
            />

            <div className="modal-actions">
              <button className="duplicate" onClick={confirmDuplicate}>
                Confirm
              </button>
              <button
                className="reject"
                onClick={() => setShowDuplicateModal(false)}
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
